import yaml, sys
d = yaml.safe_load(open('/tmp/verify_physics.yaml'))
errs = []
# 1. total_mass
if d['mass']['total_mass']['value'] != 0.632:
    errs.append(f'total_mass={d["mass"]["total_mass"]["value"]}, expected 0.632')
# 2. per_link_masses exists
if 'per_link_masses' not in d['mass']:
    errs.append('missing per_link_masses section')
else:
    plm = d['mass']['per_link_masses']
    expected = {'base': 0.147, 'shoulder': 0.100, 'upper_arm': 0.103, 'lower_arm': 0.104, 'wrist': 0.079, 'gripper': 0.087, 'jaw': 0.012}
    for link, mass in expected.items():
        if link not in plm:
            errs.append(f'missing link: {link}')
        elif plm[link]['value'] != mass:
            errs.append(f'{link} mass={plm[link]["value"]}, expected {mass}')
        elif 'unit' not in plm[link]:
            errs.append(f'{link} missing unit field')
    # 3. sum check
    s = round(sum(v['value'] for v in plm.values()), 3)
    if s != 0.632:
        errs.append(f'per_link sum={s}, expected 0.632')
# 4. preserved sections
for sec in ['simulation', 'friction', 'damping', 'contact']:
    if sec not in d:
        errs.append(f'missing preserved section: {sec}')
if errs:
    print('FAIL: ' + '; '.join(errs))
    sys.exit(1)
print('OK: physics.yaml validated')
"

git show auto-claude/005-phase3-ssot:params/control.yaml > /tmp/verify_control.yaml && python3 -c "
import yaml, sys
d = yaml.safe_load(open('/tmp/verify_control.yaml'))
errs = []
# 1. joint_names
expected_names = ['shoulder_pan', 'shoulder_lift', 'elbow_flex', 'wrist_flex', 'wrist_roll', 'gripper']
if 'joint_names' not in d:
    errs.append('missing joint_names')
elif d['joint_names']['value'] != expected_names:
    errs.append(f'joint_names={d["joint_names"]["value"]}')
# 2. decimation
if d['decimation']['value'] != 10:
    errs.append(f'decimation={d["decimation"]["value"]}, expected 10')
# 3. drive gains
if d['drive']['stiffness']['value'] != 40.0:
    errs.append(f'stiffness={d["drive"]["stiffness"]["value"]}')
if d['drive']['damping']['value'] != 4.0:
    errs.append(f'damping={d["drive"]["damping"]["value"]}')
if d['drive']['max_effort']['value'] != 5.0:
    errs.append(f'max_effort={d["drive"]["max_effort"]["value"]}')
# 4. joint_limits
exp_min = [-1.9199, -1.7453, -1.5708, -1.6581, -2.7925, 0.1745]
exp_max = [1.9199, 1.7453, 1.5708, 1.6581, 2.7925, 1.7453]
actual_min = d['joint_limits']['position_min']['value']
actual_max = d['joint_limits']['position_max']['value']
if len(actual_min) != 6:
    errs.append(f'position_min has {len(actual_min)} entries')
elif actual_min != exp_min:
    errs.append(f'position_min mismatch: {actual_min}')
if len(actual_max) != 6:
    errs.append(f'position_max has {len(actual_max)} entries')
elif actual_max != exp_max:
    errs.append(f'position_max mismatch: {actual_max}')
# 5. per_joint_overrides
if 'per_joint_overrides' not in d:
    errs.append('per_joint_overrides missing (still commented?)')
else:
    pjo = d['per_joint_overrides']
    for jn in expected_names:
        if jn not in pjo:
            errs.append(f'per_joint_overrides missing joint: {jn}')
        else:
            if pjo[jn].get('stiffness') != 40.0:
                errs.append(f'{jn} override stiffness != 40.0')
            if pjo[jn].get('damping') != 4.0:
                errs.append(f'{jn} override damping != 4.0')
# 6. control_frequency
if d['control_frequency']['value'] != 20.0:
    errs.append(f'control_frequency={d["control_frequency"]["value"]}')
if errs:
    print('FAIL: ' + '; '.join(errs))
    sys.exit(1)
print('OK: control.yaml validated')
"

