git show auto-claude/005-phase3-ssot:params/physics.yaml > /tmp/verify_physics.yaml && python3 -c "
import yaml, re, sys
d = yaml.safe_load(open('/tmp/verify_physics.yaml'))
errs = []
def check_snake_case(key, path):
    if not re.match(r'^[a-z][a-z0-9_]*$', key):
        errs.append(f'non-snake_case key: {path}.{key}')
def check_param(param, path):
    if isinstance(param, dict):
        if 'value' in param:
            # This is a leaf parameter
            if 'unit' not in param:
                errs.append(f'{path}: missing unit')
            if 'description' not in param:
                errs.append(f'{path}: missing description')
        else:
            for k, v in param.items():
                check_snake_case(k, path)
                check_param(v, f'{path}.{k}')

for section_name, section_val in d.items():
    check_snake_case(section_name, '')
    if isinstance(section_val, dict):
        for k, v in section_val.items():
            check_snake_case(k, section_name)
            check_param(v, f'{section_name}.{k}')
if errs:
    print('FAIL: ' + '; '.join(errs[:5]))
    sys.exit(1)
print('OK: physics.yaml schema compliant')
"

git show auto-claude/005-phase3-ssot:params/control.yaml > /tmp/verify_control.yaml && python3 -c "
import yaml, re, sys
d = yaml.safe_load(open('/tmp/verify_control.yaml'))
errs = []
def check_snake_case(key, path):
    if not re.match(r'^[a-z][a-z0-9_]*$', key):
        errs.append(f'non-snake_case key: {path}.{key}')
# Check top-level standard params have value/unit/description
standard_params = ['control_frequency', 'decimation', 'action_delay', 'observation_delay', 'action_scale']
for param_name in standard_params:
    check_snake_case(param_name, '')
    if param_name not in d:
        errs.append(f'missing param: {param_name}')
    else:
        p = d[param_name]
        for field in ['value', 'unit', 'description']:
            if field not in p:
                errs.append(f'{param_name}: missing {field}')
# Check drive sub-params
if 'drive' in d:
    for dp in ['stiffness', 'damping', 'max_effort']:
        if dp in d['drive']:
            for field in ['value', 'unit', 'description']:
                if field not in d['drive'][dp]:
                    errs.append(f'drive.{dp}: missing {field}')
# Check joint_names has unit field
if 'joint_names' in d:
    jn = d['joint_names']
    for field in ['value', 'unit', 'description']:
        if field not in jn:
            errs.append(f'joint_names: missing {field}')
# Check per_joint_overrides keys are snake_case
if 'per_joint_overrides' in d:
    for jname in d['per_joint_overrides']:
        check_snake_case(jname, 'per_joint_overrides')
if errs:
    print('FAIL: ' + '; '.join(errs[:5]))
    sys.exit(1)
print('OK: control.yaml schema compliant')
"
